import { describe, expect, it, vi } from 'vitest';

import { parseTerminalProsodyMode } from '../src/terminal-prosody-mode';

describe('parseTerminalProsodyMode', () => {
  it('defaults to OFF (opt-in) until the prosody-speed work lands', () => {
    // Polarity inverted: terminal-prosody biasing is ~15-19s/step on CPU, so an
    // unset env must NOT trigger it. Callers opt in per request (enable_prosody)
    // or force it on with TERMINAL_PROSODY=bias.
    expect(parseTerminalProsodyMode(undefined)).toBe('off');
    expect(parseTerminalProsodyMode('')).toBe('off');
    expect(parseTerminalProsodyMode('   ')).toBe('off');
  });

  it('still honors explicit env-level enable (bias)', () => {
    expect(parseTerminalProsodyMode('bias')).toBe('bias');
    expect(parseTerminalProsodyMode('on')).toBe('bias');
    expect(parseTerminalProsodyMode('1')).toBe('bias');
    expect(parseTerminalProsodyMode('true')).toBe('bias');
  });

  it('keeps explicit observe telemetry-only mode', () => {
    expect(parseTerminalProsodyMode('observe')).toBe('observe');
    expect(parseTerminalProsodyMode('telemetry')).toBe('observe');
  });

  it('allows env-level disable switches', () => {
    expect(parseTerminalProsodyMode('off')).toBe('off');
    expect(parseTerminalProsodyMode('0')).toBe('off');
    expect(parseTerminalProsodyMode('false')).toBe('off');
    expect(parseTerminalProsodyMode('disable')).toBe('off');
    expect(parseTerminalProsodyMode('disabled')).toBe('off');
    expect(parseTerminalProsodyMode('no')).toBe('off');
  });

  it('disables unknown explicit values with a warning', () => {
    const warn = vi.fn();
    expect(parseTerminalProsodyMode('maybe', warn)).toBe('off');
    expect(warn.mock.calls.length).toBe(1);
  });
});
